def gen(rng, size):
    n = max(1, min(size, 1000))
    alphabet = rng.randint(1, min(26, n))
    word = [chr(ord('a') + rng.randrange(alphabet)) for _ in range(n)]
    lcp = [[0] * n for _ in range(n)]
    for i in range(n - 1, -1, -1):
        for j in range(n - 1, -1, -1):
            if word[i] == word[j]:
                lcp[i][j] = (lcp[i + 1][j + 1] + 1) if i + 1 < n and j + 1 < n else 1
    return [lcp]

