class Solution:
    def findTheString(self, lcp):
        n = len(lcp)

        def rgs(i, maxval, cur):
            if i == n:
                yield cur[:]
                return
            for v in range(0, maxval + 2):
                cur.append(v)
                yield from rgs(i + 1, max(maxval, v), cur)
                cur.pop()

        best = None
        for pattern in rgs(0, -1, []):
            k = max(pattern) + 1 if pattern else 0
            if k > 26:
                continue
            w = ''.join(chr(ord('a') + v) for v in pattern)
            actual = [[0] * n for _ in range(n)]
            ok = True
            for i in range(n - 1, -1, -1):
                for j in range(n - 1, -1, -1):
                    if w[i] == w[j]:
                        actual[i][j] = (actual[i + 1][j + 1] + 1) if i + 1 < n and j + 1 < n else 1
                    if actual[i][j] != lcp[i][j]:
                        ok = False
            if ok and (best is None or w < best):
                best = w
        return best if best is not None else ''

