class Solution:
    def findTheString(self, lcp):
        n = len(lcp)
        word = [''] * n
        letter = 'a'
        for i in range(n):
            if word[i] == '':
                if letter > 'z':
                    return ''
                for j in range(i, n):
                    if lcp[i][j] > 0:
                        word[j] = letter
                letter = chr(ord(letter) + 1)
        w = ''.join(word)
        actual = [[0] * n for _ in range(n)]
        for i in range(n - 1, -1, -1):
            for j in range(n - 1, -1, -1):
                if w[i] == w[j]:
                    actual[i][j] = (actual[i + 1][j + 1] + 1) if i + 1 < n and j + 1 < n else 1
        for i in range(n):
            for j in range(n):
                if actual[i][j] != lcp[i][j]:
                    return ''
        return w

