var findTheString = function(lcp) {
    const n = lcp.length;
    const word = new Array(n).fill('');
    let letter = 'a';
    for (let i = 0; i < n; i++) {
        if (word[i] === '') {
            if (letter > 'z') return '';
            for (let j = i; j < n; j++) {
                if (lcp[i][j] > 0) word[j] = letter;
            }
            letter = String.fromCharCode(letter.charCodeAt(0) + 1);
        }
    }
    const w = word.join('');
    const actual = Array.from({ length: n }, () => new Array(n).fill(0));
    for (let i = n - 1; i >= 0; i--) {
        for (let j = n - 1; j >= 0; j--) {
            if (w[i] === w[j]) {
                actual[i][j] = (i + 1 < n && j + 1 < n) ? actual[i + 1][j + 1] + 1 : 1;
            }
        }
    }
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (actual[i][j] !== lcp[i][j]) return '';
        }
    }
    return w;
};
